using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class PurchaseOrdersTraining : TrainingContentBase
{
    public PurchaseOrdersTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Purchase Orders Overview",
            Slug = "purchase-orders-overview",
            Summary = "What purchase orders are, the PO lifecycle from draft to close, line items, receiving workflow, blanket POs, and how POs connect to vendors, inventory, and jobs.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/purchase-orders"]""",
            Tags = """["purchase-orders","procurement","receiving","vendors"]""",
            ContentJson = """{"body":"## Purchase Orders Overview\n\nThe Purchase Orders module manages your procurement workflow — from requesting materials to receiving them on your dock. Every purchase order (PO) tracks what you ordered, from which vendor, how much you paid, and what has arrived so far.\n\n### What Is a Purchase Order?\n\nA purchase order is a formal document sent to a vendor authorizing them to supply specific parts at agreed prices. Each PO contains:\n- **Header** — vendor, optional linked job, expected delivery date, notes\n- **Line items** — one or more parts with ordered quantity and unit price\n- **Receiving records** — what has actually arrived against each line\n\n### PO Lifecycle\n\nEvery purchase order moves through a defined status workflow:\n\n1. **Draft** — PO is being prepared. Lines can be added, edited, or removed. The PO has not been sent to the vendor yet.\n2. **Submitted** — PO has been sent to the vendor. You are waiting for their acknowledgment.\n3. **Acknowledged** — The vendor has confirmed the order. You can now begin receiving items.\n4. **Partially Received** — Some line items have been received, but not all. The system tracks received vs. remaining quantities per line.\n5. **Received** — All line items are fully received. The PO is complete.\n6. **Closed** — The PO has been formally closed after receiving is complete. No further receiving is possible.\n7. **Cancelled** — The PO was cancelled before completion. Only Draft, Submitted, and Acknowledged POs can be cancelled.\n\n### Line Items\n\nEach line item on a PO represents a specific part you are ordering:\n- **Part** — selected from your Parts Catalog (assemblies are excluded)\n- **Ordered Quantity** — how many units you need\n- **Unit Price** — cost per unit (auto-fills from the part's default price if available)\n- **Line Total** — automatically calculated as quantity times unit price\n- **Received Quantity** — updated as items arrive\n- **Remaining Quantity** — ordered minus received, calculated automatically\n\nThe PO total is the sum of all line totals.\n\n### Receiving Workflow\n\nWhen materials arrive, you open the Receive Items dialog from the PO detail:\n1. The dialog shows all lines that still have remaining quantity\n2. Enter the quantity received for each line (or click Receive All to fill in remaining quantities)\n3. Save to record the receipt\n\nReceiving updates the line's received quantity and may change the PO status:\n- If some lines still have remaining quantity → **Partially Received**\n- If all lines are fully received → **Received**\n\nEach receiving event creates a receiving record with the quantity, who received it, and optional notes.\n\n### Blanket Purchase Orders\n\nA blanket PO is a long-term agreement with a vendor for a total quantity at an agreed unit price. Instead of ordering everything at once, you create releases against the blanket PO over time:\n- **Blanket Total Quantity** — the total committed quantity\n- **Agreed Unit Price** — the negotiated price per unit\n- **Blanket Expiration Date** — when the agreement expires\n- **Releases** — individual delivery requests drawn against the blanket quantity\n\nEach release specifies a line item, quantity, and requested delivery date. Releases have their own status tracking (Open, Sent, Partial Received, Received, Cancelled).\n\n### How POs Connect to Other Features\n\n**Vendors:** Every PO is linked to a vendor. The vendor dropdown on the PO form pulls from your Vendors module. Clicking the vendor name in the PO detail opens the vendor record.\n\n**Jobs:** A PO can optionally be linked to a specific job (e.g., ordering materials for a production run). The job link appears in the PO detail and list table.\n\n**Parts Catalog:** PO line items reference parts from your Parts Catalog. When selecting a part, the unit price auto-fills from the part's default price if one exists.\n\n**Inventory:** Receiving items against a PO can update inventory quantities when a storage location is specified on the receiving record.\n\n**Kanban Board:** When a job on the kanban board reaches the 'Materials Ordered' stage, the associated PO tracks what was ordered and when it arrives.\n\n### When to Use Purchase Orders\n\n- When ordering raw materials, components, or supplies from a vendor\n- When you need to track what has been ordered vs. what has arrived\n- When linking material purchases to specific jobs for cost tracking\n- When setting up blanket agreements for recurring material needs\n- When you need a paper trail for procurement (PDF export available)","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Purchase Orders — Guided Tour",
            Slug = "purchase-orders-walkthrough",
            Summary = "A guided tour of the purchase orders list page: search, vendor filter, status filter, data table, creating POs, and viewing PO details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/purchase-orders"]""",
            Tags = """["purchase-orders","procurement","walkthrough"]""",
            ContentJson = """{"appRoute":"/purchase-orders","startButtonLabel":"Tour Purchase Orders","steps":[{"element":"[data-testid='new-po-btn']","popover":{"title":"Create Purchase Order","description":"Click here to create a new PO. You'll select a vendor, optionally link a job, add line items with parts and quantities, and submit when ready. The PO number is auto-generated.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search POs","description":"Search by PO number, vendor name, or job number. Results update in real time as you type. Use this to quickly find a specific order.","side":"bottom"}},{"element":".filters-bar app-select:first-of-type","popover":{"title":"Vendor Filter","description":"Filter the table to show POs from a specific vendor. Select a vendor name or choose 'All Vendors' to see everything. The vendor list is loaded from your Vendors module.","side":"bottom"}},{"element":".filters-bar app-select:last-of-type","popover":{"title":"Status Filter","description":"Filter by PO status: Draft (not yet sent), Submitted (sent to vendor), Acknowledged (vendor confirmed), Partially Received (some items arrived), Received (all items arrived), Closed, or Cancelled. Each status shows as a color-coded chip.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Purchase Orders Table","description":"Click any row to open the PO detail dialog. You'll see the PO number, vendor, linked job, status chip, line count, ordered vs. received quantities, expected delivery date, and creation date. Click column headers to sort. Use the gear icon to customize visible columns.","side":"top"}},{"element":"app-data-table thead th:nth-child(5)","popover":{"title":"Status Column","description":"Status is shown as a color-coded chip: gray for Draft, blue for Submitted, purple for Acknowledged, orange for Partially Received, green for Received, gray for Closed, and red for Cancelled. You can also filter by status using the column filter.","side":"bottom"}},{"element":"app-data-table thead th:nth-child(7)","popover":{"title":"Ordered vs. Received","description":"The Ordered column shows total units across all lines. The Received column shows how many have arrived. When Received equals Ordered, the PO status automatically moves to Received.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Purchase Orders Field Reference",
            Slug = "purchase-orders-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and action in the Purchase Orders module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/purchase-orders"]""",
            Tags = """["purchase-orders","procurement","reference"]""",
            ContentJson = """{"title":"Purchase Orders Field Reference","groups":[{"heading":"PO Header Fields (Create Dialog)","items":[{"label":"Vendor (required)","value":"Dropdown selecting the vendor for this PO. Populated from the Vendors module. Must select a vendor before saving."},{"label":"Job (optional)","value":"Links the PO to a specific job. Useful for tracking material costs against a production run. Appears as a clickable entity link in the detail view."},{"label":"Notes (optional)","value":"Textarea for free-form notes about the order — special instructions, shipping preferences, or internal comments."}]},{"heading":"Line Item Fields (Create Dialog)","items":[{"label":"Part (required)","value":"Autocomplete field searching the Parts Catalog. Shows part number and description. Assembly-type parts are excluded — only purchasable parts appear."},{"label":"Ordered Quantity (required)","value":"Number input, minimum 1. How many units of this part to order. Defaults to 1 when adding a new line."},{"label":"Unit Price (required)","value":"Number input, minimum 0. Cost per unit. Auto-fills from the part's default price when a part is selected (indicated by a tooltip). Can be manually overridden."},{"label":"Line Total (computed)","value":"Displayed per line: Ordered Quantity multiplied by Unit Price. Not directly editable."},{"label":"Add Line button","value":"Adds the current part/quantity/price as a new line item. The line form resets after adding. At least one line item is required to save the PO."},{"label":"Remove Line (trash icon)","value":"Removes a line item from the PO before saving. Icon button on each line row."},{"label":"PO Total (computed)","value":"Sum of all line totals. Displayed at the bottom of the line items section in the create dialog."}]},{"heading":"PO Detail Fields (Read-Only)","items":[{"label":"PO Number","value":"Auto-generated unique identifier (e.g., PO-00042). Displayed prominently in the detail header."},{"label":"Status","value":"Color-coded chip showing current lifecycle stage. See PO Statuses section below."},{"label":"Vendor","value":"Clickable entity link to the vendor record. Opens vendor detail dialog."},{"label":"Job","value":"Clickable entity link to the linked job (if any). Opens job detail dialog."},{"label":"Expected Delivery Date","value":"Date when materials are expected to arrive. Shown in MM/dd/yyyy format."},{"label":"Submitted Date","value":"When the PO was sent to the vendor. Null until submitted."},{"label":"Acknowledged Date","value":"When the vendor confirmed the order. Null until acknowledged."},{"label":"Received Date","value":"When all items were fully received. Null until fully received."},{"label":"Created / Updated","value":"Timestamps showing when the PO was created and last modified."}]},{"heading":"Line Item Detail Fields","items":[{"label":"Part Number","value":"The part's identifier from the Parts Catalog. Clickable entity link to open part detail."},{"label":"Description","value":"Part description pulled from the catalog."},{"label":"Ordered Quantity","value":"Number of units ordered on this line."},{"label":"Received Quantity","value":"Number of units received so far. Updated via the Receive Items workflow."},{"label":"Remaining Quantity","value":"Ordered minus Received. Computed automatically. When zero, the line is fully received."},{"label":"Unit Price","value":"Cost per unit for this line."},{"label":"Line Total","value":"Ordered Quantity times Unit Price."},{"label":"Notes","value":"Optional per-line notes."}]},{"heading":"PO Statuses","items":[{"label":"Draft (gray chip)","value":"PO is being prepared. Can add/remove lines, edit, delete, or cancel. Not yet sent to vendor."},{"label":"Submitted (blue chip)","value":"PO has been sent to vendor. Waiting for acknowledgment. Can still cancel."},{"label":"Acknowledged (purple chip)","value":"Vendor confirmed the order. Can now receive items. Can still cancel."},{"label":"Partially Received (orange chip)","value":"Some items received but not all. Receive Items button remains available. Cannot cancel."},{"label":"Received (green chip)","value":"All line items fully received. Can be closed. No further receiving needed."},{"label":"Closed (gray chip)","value":"PO formally closed after receiving is complete. No further actions possible."},{"label":"Cancelled (red chip)","value":"PO was cancelled. Only Draft, Submitted, and Acknowledged POs can be cancelled. Requires confirmation dialog."}]},{"heading":"Receiving Fields (Receive Items Dialog)","items":[{"label":"Receivable Lines","value":"Shows only lines with remaining quantity greater than zero. Fully received lines are excluded."},{"label":"Quantity to Receive (per line)","value":"Number input per line, minimum 0, maximum is the remaining quantity. Enter how many units arrived for each line."},{"label":"Receive All button","value":"Fills in the remaining quantity for every receivable line. Convenience action for when the entire shipment arrives complete."},{"label":"Save","value":"Records the receiving event. Updates received quantities on each line. May change PO status to Partially Received or Received."}]},{"heading":"Blanket PO Fields","items":[{"label":"Is Blanket","value":"Toggle indicating this is a blanket (long-term) PO rather than a one-time order."},{"label":"Blanket Total Quantity","value":"Total quantity committed under the blanket agreement."},{"label":"Agreed Unit Price","value":"Negotiated price per unit for the blanket agreement."},{"label":"Blanket Expiration Date","value":"When the blanket agreement expires."},{"label":"Released Quantity","value":"Sum of quantities from all releases created against this blanket."},{"label":"Remaining Quantity","value":"Blanket Total minus Released. Computed automatically."}]},{"heading":"Blanket Release Fields","items":[{"label":"Line Item (required)","value":"Dropdown selecting which PO line item this release draws from."},{"label":"Quantity (required)","value":"Number of units for this release. Minimum 0.01."},{"label":"Requested Delivery Date (required)","value":"When you need this release delivered."},{"label":"Notes (optional)","value":"Free-form notes for this release."},{"label":"Release Status","value":"Open (blue), Sent (purple), Partial Received (orange), Received (green), Cancelled (red)."}]},{"heading":"Table Columns (List Page)","items":[{"label":"PO Number","value":"Sortable. Auto-generated PO identifier. Width: 120px."},{"label":"Vendor","value":"Sortable. Vendor company name."},{"label":"Job","value":"Sortable. Linked job number, if any. Width: 100px."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip. Width: 140px."},{"label":"Lines","value":"Sortable, center-aligned. Number of line items on the PO. Width: 70px."},{"label":"Ordered","value":"Sortable, center-aligned. Total ordered quantity across all lines. Width: 90px."},{"label":"Received","value":"Sortable, center-aligned. Total received quantity across all lines. Width: 90px."},{"label":"Expected","value":"Sortable, date type. Expected delivery date. Width: 110px."},{"label":"Created","value":"Sortable, date type. When the PO was created. Width: 110px."}]},{"heading":"Buttons and Actions","items":[{"label":"New Purchase Order (primary button)","value":"Opens the PO creation dialog. data-testid: new-po-btn"},{"label":"Save (create dialog)","value":"Creates the PO with all line items. Disabled when form is invalid, no lines added, or save is in progress."},{"label":"Cancel (create dialog)","value":"Closes the dialog without saving."},{"label":"Submit PO","value":"Sends the PO to the vendor. Changes status from Draft to Submitted. Available only when status is Draft."},{"label":"Acknowledge PO","value":"Marks vendor acknowledgment. Changes status from Submitted to Acknowledged. Available only when status is Submitted."},{"label":"Receive Items","value":"Opens the receiving dialog. Available when status is Acknowledged or Partially Received."},{"label":"Close PO","value":"Formally closes a fully received PO. Available only when status is Received."},{"label":"Cancel PO","value":"Cancels the PO with confirmation dialog. Available when status is Draft, Submitted, or Acknowledged."},{"label":"Delete PO","value":"Permanently removes a draft PO with confirmation dialog. Available only when status is Draft. Severity: danger."},{"label":"Row click (list table)","value":"Opens the PO detail dialog showing header info, line items with quantities, receiving history, and available actions."},{"label":"Create Release (blanket POs)","value":"Opens dialog to create a new release against the blanket PO. Specifies line, quantity, and delivery date."}]},{"heading":"Validation Rules","items":[{"label":"Vendor","value":"Required. Must select a vendor from the dropdown."},{"label":"Line Items","value":"At least one line item is required. Validation popover shows 'At least one line item is required' when no lines exist."},{"label":"Part (line)","value":"Required. Must select a part from the autocomplete."},{"label":"Ordered Quantity (line)","value":"Required. Must be at least 1."},{"label":"Unit Price (line)","value":"Required. Must be 0 or greater."},{"label":"Receive Quantity","value":"Minimum 0, maximum is the remaining quantity for that line. At least one line must have quantity greater than 0 to save."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save shows a validation popover listing which fields need attention."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Purchase Orders Knowledge Check",
            Slug = "purchase-orders-quiz",
            Summary = "Test your knowledge of the Purchase Orders module: lifecycle, receiving, line items, blanket POs, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["purchase-orders","procurement","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"po1","text":"You need to order 500 aluminum brackets from a vendor for an upcoming production run. What is the first step?","options":[{"id":"a","text":"Go to Inventory and create a stock adjustment for 500 brackets"},{"id":"b","text":"Navigate to Purchase Orders, click New Purchase Order, select the vendor, and add a line item for the brackets","isCorrect":true},{"id":"c","text":"Email the vendor directly and update the job notes afterward"},{"id":"d","text":"Go to the Parts Catalog and change the bracket's quantity on hand"}],"explanation":"Create a PO by clicking New Purchase Order. Select the vendor, add a line item for the bracket part with quantity 500, and save. The PO starts in Draft status ready for submission."},{"id":"po2","text":"A PO is in Draft status. Which of the following actions are available?","options":[{"id":"a","text":"Submit, Cancel, Delete, and Edit","isCorrect":true},{"id":"b","text":"Receive Items and Close"},{"id":"c","text":"Only Submit — no other actions until the vendor responds"},{"id":"d","text":"Acknowledge and Receive Items"}],"explanation":"Draft POs can be submitted to the vendor, cancelled, deleted, or edited. Receiving is not available until the vendor acknowledges the order. Delete is only available for Draft POs."},{"id":"po3","text":"You submitted a PO to your vendor and they confirmed receipt. What status should you set the PO to?","options":[{"id":"a","text":"Partially Received — since the vendor received it"},{"id":"b","text":"Acknowledged — the vendor has confirmed the order","isCorrect":true},{"id":"c","text":"Received — because the vendor received the PO document"},{"id":"d","text":"Closed — the submission process is complete"}],"explanation":"Acknowledged means the vendor has confirmed the order. This is different from Received, which means your shop has received the physical materials. The Acknowledge action is available when the PO is in Submitted status."},{"id":"po4","text":"A PO has 3 line items. You receive items for 2 of them, but the third hasn't arrived yet. What status does the PO move to?","options":[{"id":"a","text":"Received — because you recorded a receiving event"},{"id":"b","text":"Partially Received — some lines are fulfilled but not all","isCorrect":true},{"id":"c","text":"Acknowledged — it stays here until everything arrives"},{"id":"d","text":"Closed — the received items are automatically closed"}],"explanation":"When some line items have been received but others still have remaining quantity, the PO moves to Partially Received. It stays in this status until all lines are fully received."},{"id":"po5","text":"When adding a line item to a PO, you select a part and the unit price auto-fills to $12.50. Where does this price come from?","options":[{"id":"a","text":"The vendor's quoted price from the last PO"},{"id":"b","text":"The part's default price in the Parts Catalog","isCorrect":true},{"id":"c","text":"The average of all previous purchase prices for this part"},{"id":"d","text":"A fixed system-wide default price for all parts"}],"explanation":"When you select a part on a PO line, the unit price auto-fills from the part's default price if one is set in the Parts Catalog. A tooltip indicates the price is from the part's list price. You can manually override this price."},{"id":"po6","text":"You want to cancel a PO that is in Partially Received status. Is this possible?","options":[{"id":"a","text":"Yes — any PO can be cancelled at any time"},{"id":"b","text":"No — only Draft, Submitted, and Acknowledged POs can be cancelled","isCorrect":true},{"id":"c","text":"Yes — but only if you return the received items first"},{"id":"d","text":"No — you must close it instead of cancelling"}],"explanation":"The Cancel action is only available for POs in Draft, Submitted, or Acknowledged status. Once items have been received (Partially Received or Received), the PO cannot be cancelled — it must proceed through the receiving workflow to Closed."},{"id":"po7","text":"In the Receive Items dialog, what does the 'Receive All' button do?","options":[{"id":"a","text":"Marks the entire PO as Received regardless of actual quantities"},{"id":"b","text":"Fills in the remaining quantity for every receivable line item","isCorrect":true},{"id":"c","text":"Creates a new receiving record with zero quantities for audit purposes"},{"id":"d","text":"Closes the PO and archives all line items"}],"explanation":"Receive All is a convenience button that fills in the remaining quantity for every line that still has outstanding items. This is useful when a complete shipment arrives and you don't need to enter quantities line by line. You still need to click Save to record the receipt."},{"id":"po8","text":"What is a blanket purchase order?","options":[{"id":"a","text":"A PO that covers all parts from a single vendor at once"},{"id":"b","text":"A long-term agreement for a total quantity at an agreed price, with individual releases over time","isCorrect":true},{"id":"c","text":"A PO template that auto-generates new POs on a schedule"},{"id":"d","text":"A PO that has been approved by management for large expenditures"}],"explanation":"A blanket PO is a long-term purchasing agreement with a vendor. You commit to a total quantity at an agreed unit price, then create individual releases over time as you need materials delivered. Each release specifies a quantity and requested delivery date."},{"id":"po9","text":"A PO line item shows Ordered: 100, Received: 75, Remaining: 25. What does this tell you?","options":[{"id":"a","text":"The vendor has shipped all 100 units but 25 were rejected during inspection"},{"id":"b","text":"75 units have arrived and been recorded; 25 units are still outstanding","isCorrect":true},{"id":"c","text":"You originally ordered 75 but increased the order to 100"},{"id":"d","text":"25 units are on backorder and the rest were cancelled"}],"explanation":"Remaining Quantity is calculated as Ordered minus Received. Here, 75 units have been physically received and recorded through the Receive Items workflow. 25 units are still expected from the vendor."},{"id":"po10","text":"You need to delete a purchase order. Under what condition is this allowed?","options":[{"id":"a","text":"Any PO can be deleted at any time by an admin"},{"id":"b","text":"Only POs in Draft status can be deleted","isCorrect":true},{"id":"c","text":"POs can be deleted only after they are Cancelled"},{"id":"d","text":"POs are never deleted — they can only be archived"}],"explanation":"The Delete action is only available for Draft POs. Once a PO has been submitted or progressed further in the lifecycle, it cannot be deleted — it can only be cancelled (if eligible) or closed. Delete requires a confirmation dialog with danger severity."},{"id":"po11","text":"You want to see all POs from a specific vendor that are waiting for materials. Which filters do you apply?","options":[{"id":"a","text":"Set the Vendor filter to the vendor name and Status filter to Acknowledged or Partially Received","isCorrect":true},{"id":"b","text":"Search for the vendor name in the search box — no other filters needed"},{"id":"c","text":"Set the Status filter to Submitted and sort by vendor name"},{"id":"d","text":"Go to the vendor's detail page and look at the PO tab"}],"explanation":"Use the Vendor dropdown to select the specific vendor, then set the Status filter. POs that are 'waiting for materials' are in Acknowledged status (vendor confirmed, awaiting shipment) or Partially Received (some items arrived, still waiting for more)."},{"id":"po12","text":"After all items on a PO are received, what is the next step to finalize the order?","options":[{"id":"a","text":"Delete the PO to clear it from the list"},{"id":"b","text":"Click Close PO to formally close the order","isCorrect":true},{"id":"c","text":"The PO automatically closes — no action needed"},{"id":"d","text":"Submit the PO again to confirm completion with the vendor"}],"explanation":"When all items are received, the PO moves to Received status. The final step is to click Close PO, which formally closes the order. This is a deliberate action — POs do not auto-close. Once closed, no further actions (receiving, cancelling) are possible."}]}"""
        });

        Log.Information("Seeded Purchase Orders training modules");
    }
}
